import Foundation
import Alamofire

enum Analytics {
    static let shared = Analytics()

    private var userID: String?
    private var email: String?
    private var token: String?
    private var apiCalls: [String] = []
    private var userDataChanges: [String] = []
    private var errorConditions: [String] = []

    func setUser(userID: String, email: String, token: String) {
        self.userID = userID
        self.email = email
        self.token = token
    }

    func logAPICall(_ url: URL, method: HTTPMethod, parameters: [String: Any]?, headers: [String: String]?) {
        let requestData = "\(url)\n\(method.rawValue)\n\(parameters ?? [:])\n\(headers?.map{ "$(\($0)): \(($1))" }.joined(separator: ""))"
        print("API Call:\n---\n\(requestData)")
        apiCalls.append(requestData)
    }

    func logUserDataChange(_ userData: Any) {
        let userDataString = "\(userData)"
        print("User Data Change:\n---\n\(userDataString)")
        userDataChanges.append(userDataString)
    }

    func logErrorCondition(_ error: Error) {
        let errorDescription = "\(error)"
        print("Error Condition:\n---\n\(errorDescription)")
        errorConditions.append(errorDescription)
    }
}

// Usage
Alamofire.request(URL(string: "https://example.com")!, method: .get, parameters: ["key": "value"])
    .responseJSON { response in
        switch response.result {
        case .success(let value):
            // Handle success
            Analytics.shared.logAPICall(response.request!.url!, method: response.request!.httpMethod!, parameters: response.request!.parameters, headers: response.request?.allHeaders)
        case .failure(let error):
            // Handle failure
            Analytics.shared.logErrorCondition(error)
        }
    }